defmodule MyAppWeb.URLController do
  use MyAppWeb, :controller

  alias HTTPoison

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, response} -> render_response(conn, response)
      {:error, reason} -> handle_error(conn, reason)
    end
  end

  defp render_response(conn, %HTTPoison.Response{body: body, status_code: code}) do
